const incoming = $input.item;
const binaryKeys = Object.keys(incoming.binary || {});

if (binaryKeys.length === 0) {
  return {
    json: {
      hasFile: false,
      chatInput: incoming.json.chatInput || '',
      sessionId: incoming.json.sessionId || ''
    }
  };
}

const key = binaryKeys[0];
const file = incoming.binary[key];

return {
  json: {
    hasFile: true,
    fileName: file.fileName || 'documento.pdf',
    mimeType: file.mimeType || '',
    sessionId: incoming.json.sessionId || '',
    chatInput: incoming.json.chatInput || ''
  },
  binary: {
    data: file
  }
};
